mapper.select:
SELECT COUNT(*) 
FROM equipment_repair
WHERE user_id = #{userId}
AND equipment_id = #{equipmentId}
AND audit_status = 0

SELECT r.id, r.equipment_id, r.equipment_number, r.equipment_name, COALESCE(r.equipment_model, e.equipment_model) AS equipment_model, COALESCE(r.equipment_image, e.equipment_image) AS equipment_image, r.equipment_type_id, et.type_name AS equipment_type_name, r.repair_status, r.user_id, r.real_name, r.repair_quantity, r.fault_description, r.fault_image, r.phone, r.repair_time, r.audit_status, r.audit_result, r.expected_return_time, r.audit_user_id, r.audit_user_name, r.audit_time, r.create_time, r.update_time FROM equipment_repair r LEFT JOIN equipment e ON r.equipment_id = e.id LEFT JOIN equipment_type et ON e.equipment_type_id = et.id
r.user_id = #{userId}
AND r.repair_status = #{repairStatus}
AND r.audit_status = #{auditStatus}
AND ( r.equipment_number LIKE CONCAT('%', #{keyword}, '%') OR r.equipment_name LIKE CONCAT('%', #{keyword}, '%') OR r.real_name LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY r.create_time DESC
